# Python 3.11+
"""Channel ADAPTERS — the pluggable delivery sinks (one per medium).

Each channel knows HOW to deliver on its medium; the router knows nothing about
SMTP vs APNs vs an SMS gateway — it just calls `send`. A failing channel raises
`ChannelDeliveryError`, which the router isolates so one bad channel never stops
the others. `make_channels` is the factory that maps the Channel enum to adapters.
"""

from abc import ABC, abstractmethod

from models import Channel, NotificationError, Notification, UnknownChannelError, User


class ChannelDeliveryError(NotificationError):
    pass


class NotificationChannel(ABC):
    channel: Channel

    @abstractmethod
    def send(self, user: User, notification: Notification) -> None:
        """Deliver the notification, or raise ChannelDeliveryError."""


class EmailChannel(NotificationChannel):
    channel = Channel.EMAIL

    def send(self, user: User, notification: Notification) -> None:
        # Real impl would call an SMTP / SES client here.
        print(f"[EMAIL] to {user.id}: {notification.type.value} — {notification.payload}")


class SmsChannel(NotificationChannel):
    channel = Channel.SMS

    def send(self, user: User, notification: Notification) -> None:
        print(f"[SMS] to {user.id}: {notification.payload}")


class PushChannel(NotificationChannel):
    channel = Channel.PUSH

    def send(self, user: User, notification: Notification) -> None:
        print(f"[PUSH] to {user.id}: {notification.payload}")


class WhatsAppChannel(NotificationChannel):
    channel = Channel.WHATSAPP

    def send(self, user: User, notification: Notification) -> None:
        print(f"[WHATSAPP] to {user.id}: {notification.payload}")


# ── test / inspection doubles ──────────────────────────────────────────────────
class CollectingChannel(NotificationChannel):
    """Records every send instead of doing IO — lets tests assert exactly-once."""

    def __init__(self, channel: Channel) -> None:
        self.channel = channel
        self.sent: list[str] = []        # notification ids delivered

    def send(self, user: User, notification: Notification) -> None:
        self.sent.append(notification.id)


class FailingChannel(NotificationChannel):
    """Always fails — used to prove channel-failure isolation."""

    def __init__(self, channel: Channel) -> None:
        self.channel = channel

    def send(self, user: User, notification: Notification) -> None:
        raise ChannelDeliveryError(f"{self.channel.value} is down")


_DEFAULT_BUILDERS: dict[Channel, type[NotificationChannel]] = {
    Channel.EMAIL: EmailChannel,
    Channel.SMS: SmsChannel,
    Channel.PUSH: PushChannel,
    Channel.WHATSAPP: WhatsAppChannel,
}


def make_channels() -> dict[Channel, NotificationChannel]:
    """Factory: build the default adapter for every channel."""
    return {ch: builder() for ch, builder in _DEFAULT_BUILDERS.items()}

# Python 3.11+
"""The routing SEAM (Strategy).

"Which channels should this notification go out on?" is the policy the product
tweaks constantly. A RoutingStrategy turns (user, notification) into an ordered
list of channels. It is a PURE decision — no IO, no shared state — so the router
can call it outside any lock.
"""

from abc import ABC, abstractmethod

from models import Channel, Notification, Severity, User


class RoutingStrategy(ABC):
    @abstractmethod
    def channels_for(self, user: User, notification: Notification) -> list[Channel]:
        """Return the channels to deliver on, in priority order (may be empty)."""


class PreferenceBasedRouting(RoutingStrategy):
    """Deliver on exactly the channels the user has opted into, in a stable order."""

    ORDER = [Channel.PUSH, Channel.EMAIL, Channel.SMS, Channel.WHATSAPP]

    def channels_for(self, user: User, notification: Notification) -> list[Channel]:
        return [ch for ch in self.ORDER if user.is_opted_in(ch)]


class SeverityRouting(RoutingStrategy):
    """Escalate by urgency: INFO -> push only; NORMAL -> push+email; CRITICAL ->
    every opted-in channel (so a payment failure reaches the user any way it can).
    """

    def channels_for(self, user: User, notification: Notification) -> list[Channel]:
        if notification.severity >= Severity.CRITICAL:
            wanted = [Channel.PUSH, Channel.EMAIL, Channel.SMS, Channel.WHATSAPP]
        elif notification.severity == Severity.NORMAL:
            wanted = [Channel.PUSH, Channel.EMAIL]
        else:
            wanted = [Channel.PUSH]
        return [ch for ch in wanted if user.is_opted_in(ch)]


class FallbackRouting(RoutingStrategy):
    """Pick the single best opted-in channel by a preference order — used when you
    want ONE delivery (cost control), escalating only if the top choice is absent.
    """

    def __init__(self, order: list[Channel] | None = None) -> None:
        self.order = order or [Channel.PUSH, Channel.EMAIL, Channel.SMS, Channel.WHATSAPP]

    def channels_for(self, user: User, notification: Notification) -> list[Channel]:
        for ch in self.order:
            if user.is_opted_in(ch):
                return [ch]
        return []
